import { MakeLogicType, afterMount, kea, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import { getCurrentTeamId } from '~/lib/utils/getAppContext'

import { evaluationsList } from './generated/api'
import type { EvaluationApi } from './generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface sentimentEvaluationAvailabilityLogicValues {
    hasLoadedSentimentEvaluations: boolean
    hasSentimentEvaluations: boolean
    sentimentEvaluations: EvaluationApi[]
    sentimentEvaluationsLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface sentimentEvaluationAvailabilityLogicActions {
    loadSentimentEvaluations: () => any
    loadSentimentEvaluationsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadSentimentEvaluationsSuccess: (
        sentimentEvaluations: EvaluationApi[],
        payload?: any
    ) => {
        sentimentEvaluations: EvaluationApi[]
        payload?: any
    }
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface sentimentEvaluationAvailabilityLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        hasSentimentEvaluations: (sentimentEvaluations: EvaluationApi[]) => boolean
    }
}

export type sentimentEvaluationAvailabilityLogicType = MakeLogicType<
    sentimentEvaluationAvailabilityLogicValues,
    sentimentEvaluationAvailabilityLogicActions,
    Record<string, any>,
    sentimentEvaluationAvailabilityLogicMeta
>

export const sentimentEvaluationAvailabilityLogic = kea<sentimentEvaluationAvailabilityLogicType>([
    path(['products', 'ai_observability', 'frontend', 'sentimentEvaluationAvailabilityLogic']),

    loaders({
        sentimentEvaluations: [
            [] as EvaluationApi[],
            {
                loadSentimentEvaluations: async () => {
                    const response = await evaluationsList(String(getCurrentTeamId()), {
                        evaluation_type: 'sentiment',
                        limit: 1,
                    })
                    return response.results || []
                },
            },
        ],
    }),

    reducers({
        hasLoadedSentimentEvaluations: [
            false as boolean,
            {
                loadSentimentEvaluationsSuccess: () => true,
                loadSentimentEvaluationsFailure: () => true,
            },
        ],
    }),

    selectors({
        hasSentimentEvaluations: [
            (s) => [s.sentimentEvaluations],
            (sentimentEvaluations: EvaluationApi[]): boolean => sentimentEvaluations.length > 0,
        ],
    }),

    afterMount(({ actions, values }) => {
        if (!values.hasLoadedSentimentEvaluations && !values.sentimentEvaluationsLoading) {
            actions.loadSentimentEvaluations()
        }
    }),
])
